#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e5+5;
const int C = 3e4+5;
const int S = 1000;
int n,Q,flag,val[N],cnt,Ans,Mex;
int dep[N],sz[N],Fath[N],mxs[N],mxd[N];
int tot,id[N],pk[N];
int stk[N],Top,gs[N],Ff[N];
vector<int> g[N];
bitset<C> bt[105][105];
vector<int> Ls;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS_init(int u,int fa){
    sz[u]=1,Fath[u]=fa;
    dep[u]=dep[fa]+1,mxd[u]=dep[u];
    for(int v:g[u])if(v^fa){
        DFS_init(v,u),sz[u]+=sz[v];
        mxd[u]=max(mxd[u],mxd[v]);
        if(!mxs[u]||sz[mxs[u]]<sz[v])mxs[u]=v;
    }if(mxd[u]-dep[u]>=S)
        id[u]=(++tot),mxd[u]=dep[u];return;
}
void DFS_yut(int u,int fa){
    for(int v:g[u])if(v^fa){
        if(id[v]){
            int px=id[stk[Top]],py=id[v];
            for(int x=v;x!=stk[Top];x=Fath[x])
                bt[px][py].set(val[x]);
            bitset<C> tmp=bt[px][py];
            for(int i=1;i<Top;i++){
                bitset<C> &tmb=bt[id[stk[i]]][py];
                tmb=bt[id[stk[i]]][px];tmb|=tmp;
            }Ff[v]=stk[Top],gs[v]=gs[stk[Top]]+1,stk[++Top]=v;
        }DFS_yut(v,u);if(id[v])Top--;
    }return;
}
void DFS_yup(int u,int fa){
    if(mxs[u])pk[mxs[u]]=pk[u],DFS_yup(mxs[u],u);
    for(int v:g[u])if(v^fa&&v!=mxs[u])
        pk[v]=v,DFS_yup(v,u);return;
}
int LCA(int u,int v){
    while(pk[u]!=pk[v])
        if(dep[pk[u]]>dep[pk[v]])u=Fath[pk[u]];
        else v=Fath[pk[v]];
    return (dep[u]<dep[v]?u:v);
}
int main(){
    n=read(),Q=read(),flag=read();
    for(int i=1;i<=n;i++)val[i]=read();
    for(int i=1;i<n;i++){
        int u=read(),v=read();
        g[u].pb(v),g[v].pb(u);
    }DFS_init(1,0);
    if(!id[1])id[1]=(++tot);
    stk[++Top]=1,gs[1]=1;
    DFS_yut(1,0);DFS_yup(1,0);
    while(Q--){
        int cnt=read();
        bitset<C> ans;ans.reset();
        while(cnt--){
            int u=read(),v=read();
            if(flag)u^=(Ans+Mex),v^=(Ans+Mex);
            int w=LCA(u,v);
            while(u!=w&&!id[u])ans.set(val[u]),u=Fath[u];
            while(v!=w&&!id[v])ans.set(val[v]),v=Fath[v];
            if(u!=w){
                int now=u;
                while(dep[Ff[now]]>=dep[w])now=Ff[now];
                if(now!=u)ans|=bt[id[now]][id[u]];
                while(now!=w)ans.set(val[now]),now=Fath[now];
            }if(v!=w){
                int now=v;
                while(dep[Ff[now]]>=dep[w])now=Ff[now];
                if(now!=v)ans|=bt[id[now]][id[v]];
                while(now!=w)ans.set(val[now]),now=Fath[now];
            }ans.set(val[w]);
        }Ans=ans.count(),Mex=0;
        while(ans[Mex]==1)Mex++;
        cout<<Ans<<" "<<Mex<<"\n";
    }
    return 0;
}
